using UnityEngine;
using FL.Gameplay.Modules.BigWorld;
public class Script {
    public static object Main() {
        var controllers = Object.FindObjectsOfType<AnimalController>();
        foreach (var c in controllers) {
            var sd = c.StateData;
            if (sd == null || sd.EntityId != 18) continue;
            return $"Dog18 State={sd.AnimalState} FollowTarget={sd.FollowTargetId} Speed={sd.MoveSpeed:F2} Pos=({c.transform.position.x:F1},{c.transform.position.y:F1},{c.transform.position.z:F1})";
        }
        return "Dog18 not found in client";
    }
}
